+package com.yottastudios.ns.collabspace.workspace.dto;
+
+import com.yottastudios.ns.collabspace.base.entity.NodeEntity;
+import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeEntity;
+import lombok.Data;
+import lombok.EqualsAndHashCode;
+import lombok.NoArgsConstructor;
+
+/**
+ * JOIN result combining space_node and node table fields.
+ * Used by listBySpaceIdJoinNode to avoid a second listByRelIds query when building the tree.
+ */
+@Data
+@EqualsAndHashCode(callSuper = true)
+@NoArgsConstructor
+public class SpaceNodeWithNodeDto extends SpaceNodeEntity {
+
+    /** node.id (aliased to avoid conflict with space_node.id) */
+    private Long nodeId;
+    /** node.parent_id */
+    private Long parentId;
+    /** node.pre_id */
+    private Long preId;
+    /** node.tree_id */
+    private String treeId;
+    /** node.node_key */
+    private Integer nodeKey;
+    /** node.node_type */
+    private String nodeType;
+
+    /** 是否有 reader 角色分配（锁定标识原始值） */
+    private Boolean isLocked;
+    /** 是否有启用的分享链接（分享标识原始值） */
+    private Boolean hasShare;
+
+    public NodeEntity toNodeEntity() {
+        NodeEntity entity = new NodeEntity();
+        entity.setId(this.nodeId);
+        entity.setRelId(this.getId());   // node.rel_id = space_node.id
+        entity.setParentId(this.parentId);
+        entity.setPreId(this.preId);
+        entity.setTreeId(this.treeId);
+        entity.setNodeKey(this.nodeKey);
+        entity.setNodeType(this.nodeType);
+        return entity;
+    }
+}
