129→        int pageSize = ro.getPageSize() != null ? ro.getPageSize() : 20;
130→
131→        LambdaQueryWrapper<FeedbackEntity> wrapper = new LambdaQueryWrapper<>();
132→        wrapper.eq(FeedbackEntity::getIsDeleted, 0);
133→
134→        if (ro.getStatus() != null) {
135→            wrapper.eq(FeedbackEntity::getStatus, ro.getStatus());
136→        }
137→        if (StrUtil.isNotBlank(ro.getDocType())) {
138→            wrapper.eq(FeedbackEntity::getDocType, ro.getDocType());
139→        }
140→        if (StrUtil.isNotBlank(ro.getFeedbackType())) {
141→            wrapper.eq(FeedbackEntity::getFeedbackType, ro.getFeedbackType());
142→        }
143→        if (StrUtil.isNotBlank(ro.getStartDate())) {
144→            try {
145→                LocalDate startDate = LocalDate.parse(ro.getStartDate(), DateTimeFormatter.ISO_LOCAL_DATE);
146→                wrapper.ge(FeedbackEntity::getFeedbackTime, startDate.atStartOfDay());
147→            } catch (java.time.format.DateTimeParseException e) {
148→                throw new BusinessException("开始日期格式错误，应为yyyy-MM-dd");
149→            }
150→        }
151→        if (StrUtil.isNotBlank(ro.getEndDate())) {
152→            try {
153→                LocalDate endDate = LocalDate.parse(ro.getEndDate(), DateTimeFormatter.ISO_LOCAL_DATE);
154→                wrapper.le(FeedbackEntity::getFeedbackTime, endDate.plusDays(1).atStartOfDay());
155→            } catch (java.time.format.DateTimeParseException e) {
156→                throw new BusinessException("结束日期格式错误，应为yyyy-MM-dd");
157→            }
158→        }
159→        if (StrUtil.isNotBlank(ro.getKeyword())) {
160→            wrapper.like(FeedbackEntity::getContent, ro.getKeyword());
161→        }
162→
163→        wrapper.orderByDesc(FeedbackEntity::getFeedbackTime);
164→
165→        IPage<FeedbackEntity> page = feedbackMapper.selectPage(new Page<>(pageNum, pageSize), wrapper);
166→
